// ─── Types ───────────────────────────────────────────────────────────────────

type Tab = "today" | "areas" | "journeys" | "room"

interface Chunk {
  id: string; journeyId: string; title: string
  completed: boolean; isInToday: boolean; pendingDaysAgo?: number
}
interface Journey {
  id: string; areaId: string; title: string; description: string
  deadline: string; createdDate: string; iconType: string; color: string; chunks: Chunk[]; archived?: boolean
}
interface Area { id: string; name: string; color: string; note: string; journeys: Journey[] }
interface Room { id: string; name: string; bgImage: string }
interface MusicTrack { id: string; name: string; isBuiltIn: boolean; src?: string }

type ModalState =
  | { type: "createArea" } | { type: "editArea"; area: Area }
  | { type: "createJourney"; areaId?: string } | { type: "editJourney"; journey: Journey }
  | { type: "createChunk"; journeyId: string } | { type: "editChunk"; chunk: Chunk }
  | { type: "addToToday" } | { type: "profile" } | { type: "music" }

