// ─── LocalStorage ─────────────────────────────────────────────────────────────

function loadLS<T>(key: string, def: T): T {
  try { const v = localStorage.getItem(`chunkify_${key}`); return v ? JSON.parse(v) : def } catch { return def }
}
function saveLS(key: string, val: unknown) {
  try { localStorage.setItem(`chunkify_${key}`, JSON.stringify(val)) } catch {}
}

// ─── Initial Data ─────────────────────────────────────────────────────────────

const mkId = () => Math.random().toString(36).slice(2, 9)

const INITIAL_AREAS: Area[] = []

// ─── Helpers ──────────────────────────────────────────────────────────────────

const fmt = (s: number) => `${Math.floor(s/60).toString().padStart(2,"0")}:${(s%60).toString().padStart(2,"0")}`

function getTodayLabel() {
  const d = new Date()
  const days = ["SUN","MON","TUE","WED","THU","FRI","SAT"]
  const months = ["JAN","FEB","MAR","APR","MAY","JUN","JUL","AUG","SEP","OCT","NOV","DEC"]
  return { day: days[d.getDay()], num: d.getDate(), month: months[d.getMonth()], year: d.getFullYear() }
}

function getAllJourneys(areas: Area[]) { return areas.flatMap(a => a.journeys) }

function findJourney(areas: Area[], jId: string) {
  for (const a of areas) { const j = a.journeys.find(j => j.id === jId); if (j) return { journey: j, area: a } }
  return null
}

function findChunk(areas: Area[], cId: string) {
  for (const a of areas) {
    for (const j of a.journeys) { const c = j.chunks.find(c => c.id === cId); if (c) return { chunk: c, journey: j, area: a } }
  }
  return null
}

function updateChunkIn(areas: Area[], chunkId: string, update: Partial<Chunk>): Area[] {
  return areas.map(a => ({ ...a, journeys: a.journeys.map(j => ({ ...j, chunks: j.chunks.map(c => c.id === chunkId ? { ...c, ...update } : c) })) }))
}

function reorder<T>(arr: T[], from: number, to: number): T[] {
  const next = [...arr]; const [item] = next.splice(from, 1); next.splice(to, 0, item); return next
}

function mkCreatedDate() {
  const d = new Date()
  const m = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"]
  return `${d.getDate().toString().padStart(2,"0")} ${m[d.getMonth()]} ${d.getFullYear()}`
}

function pendingLabel(days?: number) {
  if (!days) return ""
  if (days === 1) return "pending from yesterday"
  return `pending from ${days} days ago`
}

// ─── Drag hook ────────────────────────────────────────────────────────────────

function useDrag(onReorder: (from: number, to: number) => void) {
  const dragRef = useRef<number | null>(null)
  const [overIdx, setOverIdx] = useState<number | null>(null)
  return (idx: number) => ({
    draggable: true as const,
    onDragStart: (e: React.DragEvent) => {
      if ((e.target as HTMLElement).closest("button")) { e.preventDefault(); return }
      e.dataTransfer.effectAllowed = "move"
      dragRef.current = idx
    },
    onDragOver: (e: React.DragEvent) => { e.preventDefault(); if (overIdx !== idx) setOverIdx(idx) },
    onDrop: (e: React.DragEvent) => {
      e.preventDefault()
      if (dragRef.current !== null && dragRef.current !== idx) onReorder(dragRef.current, idx)
      dragRef.current = null; setOverIdx(null)
    },
    onDragEnd: () => { dragRef.current = null; setOverIdx(null) },
    style: { borderTop: overIdx === idx ? `2px solid ${INK_RED}` : undefined, cursor: "grab" } as React.CSSProperties,
  })
}

