// ─── Room Dropdown ────────────────────────────────────────────────────────────

function RoomDropdown({ rooms, currentRoomId, onSwitch, small = false }: {
  rooms: Room[]; currentRoomId: string; onSwitch: (id: string) => void; small?: boolean
}) {
  const [open, setOpen] = useState(false)
  const ref = useRef<HTMLDivElement>(null)
  const current = rooms.find(r => r.id === currentRoomId) || rooms[0]

  useEffect(() => {
    if (!open) return
    const h = (e: MouseEvent) => { if (ref.current && !ref.current.contains(e.target as Node)) setOpen(false) }
    document.addEventListener("mousedown", h); return () => document.removeEventListener("mousedown", h)
  }, [open])

  return (
    <div className="relative" ref={ref}>
      <button onClick={() => setOpen(o => !o)} className="flex items-center gap-1"
        style={{ fontFamily: F_HEAD, color: INK_BLACK, fontSize: small ? "0.7rem" : "0.8rem" }}>
        <span>🪑</span><span>{current.name}</span><ChevronDown size={small ? 9 : 11}/>
      </button>
      {open && (
        <div className="absolute top-full left-0 mt-1 rounded-xl shadow-xl z-50 overflow-hidden min-w-36"
          style={{ backgroundColor: PAPER_LIGHT, border: "1px solid rgba(0,0,0,0.12)" }}>
          {rooms.map(r => (
            <div key={r.id} className="flex items-center gap-2 px-3 py-2 cursor-pointer hover:bg-black/5"
              onClick={() => { onSwitch(r.id); setOpen(false) }}>
              <div className="w-10 h-7 rounded overflow-hidden flex-shrink-0">
                <img src={r.bgImage} alt={r.name} className="w-full h-full object-cover"/>
              </div>
              <span className="flex-1 text-xs" style={{ fontFamily: F_HEAD, color: INK_BLACK }}>{r.name}</span>
              {r.id === currentRoomId && <Check size={11} style={{ color: INK_RED }}/>}
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

// ─── Form components ──────────────────────────────────────────────────────────

function Modal({ open, onClose, title, children, wide = false }: {
  open: boolean; onClose: () => void; title: string; children: React.ReactNode; wide?: boolean
}) {
  if (!open) return null
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4"
      style={{ backgroundColor: "rgba(26,20,16,0.65)" }}
      onClick={e => { if (e.target === e.currentTarget) onClose() }}>
      <div className="relative rounded-2xl p-5 shadow-2xl overflow-y-auto max-h-[90vh]"
        style={{ backgroundColor: PAPER_LIGHT, width: wide ? 520 : 380, border: "1px solid rgba(0,0,0,0.1)" }}>
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-base font-bold" style={{ fontFamily: F_HEAD, color: INK_BLACK }}>{title}</h2>
          <button onClick={onClose} className="w-7 h-7 rounded-full flex items-center justify-center"
            style={{ color: MUTED, backgroundColor: "rgba(0,0,0,0.06)" }}><X size={14}/></button>
        </div>
        {children}
      </div>
    </div>
  )
}

function FIn({ label, value, onChange, placeholder }: {
  label: string; value: string; onChange: (v: string) => void; placeholder?: string
}) {
  return (
    <div className="mb-3">
      <label className="block text-xs font-medium mb-1" style={{ color: MUTED, fontFamily: F_META }}>{label}</label>
      <input value={value} placeholder={placeholder} onChange={e => onChange(e.target.value)}
        className="w-full px-3 py-2 rounded-lg text-sm outline-none border"
        style={{ borderColor: "rgba(0,0,0,0.15)", backgroundColor: "rgba(255,255,255,0.5)", color: INK_BLACK, fontFamily: F_BODY }}/>
    </div>
  )
}

function FTa({ label, value, onChange, placeholder }: {
  label: string; value: string; onChange: (v: string) => void; placeholder?: string
}) {
  return (
    <div className="mb-3">
      <label className="block text-xs font-medium mb-1" style={{ color: MUTED, fontFamily: F_META }}>{label}</label>
      <textarea value={value} placeholder={placeholder} rows={3} onChange={e => onChange(e.target.value)}
        className="w-full px-3 py-2 rounded-lg text-sm outline-none border resize-none"
        style={{ borderColor: "rgba(0,0,0,0.15)", backgroundColor: "rgba(255,255,255,0.5)", color: INK_BLACK, fontFamily: F_BODY }}/>
    </div>
  )
}

function ColorPicker({ selected, onChange }: { selected: string; onChange: (c: string) => void }) {
  return (
    <div className="mb-3">
      <label className="block text-xs font-medium mb-1.5" style={{ color: MUTED, fontFamily: F_META }}>Color</label>
      <div className="flex flex-wrap gap-2">
        {AREA_COLORS.map(c => (
          <button key={c} onClick={() => onChange(c)} className="w-6 h-6 rounded-full"
            style={{ backgroundColor: c, outline: selected === c ? `3px solid ${INK_BLACK}` : "2px solid transparent",
              outlineOffset: 2, transform: selected === c ? "scale(1.15)" : "scale(1)" }}/>
        ))}
      </div>
    </div>
  )
}

function IconPicker({ selected, onChange }: { selected: string; onChange: (i: string) => void }) {
  return (
    <div className="mb-3">
      <label className="block text-xs font-medium mb-1.5" style={{ color: MUTED, fontFamily: F_META }}>Icon</label>
      <div className="flex flex-wrap gap-2">
        {ICON_TYPES.map(icon => (
          <button key={icon} onClick={() => onChange(icon)} className="w-8 h-8 rounded-lg flex items-center justify-center"
            style={{ backgroundColor: selected === icon ? INK_BLACK : "rgba(0,0,0,0.08)",
              border: selected === icon ? `2px solid ${INK_BLACK}` : "2px solid transparent" }}>
            <IconGlyph type={icon} size={16} color={selected === icon ? "white" : MUTED}/>
          </button>
        ))}
      </div>
    </div>
  )
}

function PBtn({ onClick, children, disabled = false }: {
  onClick: () => void; children: React.ReactNode; disabled?: boolean
}) {
  return (
    <button onClick={onClick} disabled={disabled} className="px-4 py-2 rounded-lg text-sm transition-opacity"
      style={{ backgroundColor: INK_RED, color: "white", fontFamily: F_QUOTE, fontSize: "1rem", opacity: disabled ? 0.5 : 1 }}>
      {children}
    </button>
  )
}

function SBtn({ onClick, children }: { onClick: () => void; children: React.ReactNode }) {
  return (
    <button onClick={onClick} className="px-4 py-2 rounded-lg text-sm"
      style={{ backgroundColor: "rgba(0,0,0,0.08)", color: INK_BLACK, fontFamily: F_BODY }}>
      {children}
    </button>
  )
}

function AddBtn({ onClick, title }: { onClick: () => void; title?: string }) {
  return (
    <button onClick={onClick} title={title}
      className="w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0"
      style={{ backgroundColor: INK_RED, boxShadow: "0 2px 8px rgba(163,59,43,0.35)" }}>
      <Plus size={16} color="white"/>
    </button>
  )
}

// ─── Chunk dots menu ──────────────────────────────────────────────────────────

function ChunkDots({ chunk, onEdit, onDelete, onToggleToday }: {
  chunk: Chunk; onEdit?: () => void; onDelete: () => void; onToggleToday?: () => void
}) {
  const [open, setOpen] = useState(false)
  const ref = useRef<HTMLDivElement>(null)
  useEffect(() => {
    if (!open) return
    const h = (e: MouseEvent) => { if (ref.current && !ref.current.contains(e.target as Node)) setOpen(false) }
    document.addEventListener("mousedown", h); return () => document.removeEventListener("mousedown", h)
  }, [open])
  const items = [
    ...(onEdit ? [{ label: "Edit", action: onEdit }] : []),
    ...(onToggleToday ? [{ label: chunk.isInToday ? "Remove from Today" : "Add to Today", action: onToggleToday }] : []),
    { label: "Delete", action: onDelete, danger: true },
  ]
  return (
    <div className="relative" ref={ref}>
      <button onClick={() => setOpen(o => !o)} className="p-1 rounded opacity-40 hover:opacity-100 transition-opacity" style={{ color: MUTED }}>
        <MoreHorizontal size={14}/>
      </button>
      {open && (
        <div className="absolute right-0 top-full mt-1 rounded-lg shadow-xl z-30 py-1 min-w-40"
          style={{ backgroundColor: PAPER_LIGHT, border: "1px solid rgba(0,0,0,0.12)" }}>
          {items.map(item => (
            <button key={item.label} onClick={() => { item.action(); setOpen(false) }}
              className="w-full text-left px-3 py-1.5 text-xs hover:bg-black/5"
              style={{ fontFamily: F_BODY, color: (item as { danger?: boolean }).danger ? INK_RED : INK_BLACK }}>
              {item.label}
            </button>
          ))}
        </div>
      )}
    </div>
  )
}

// ─── Journey dots menu ────────────────────────────────────────────────────────

function JourneyDots({ onEdit, onDelete, onArchive }: {
  onEdit: () => void; onDelete: () => void; onArchive: () => void
}) {
  const [open, setOpen] = useState(false)
  const ref = useRef<HTMLDivElement>(null)
  useEffect(() => {
    if (!open) return
    const h = (e: MouseEvent) => { if (ref.current && !ref.current.contains(e.target as Node)) setOpen(false) }
    document.addEventListener("mousedown", h); return () => document.removeEventListener("mousedown", h)
  }, [open])
  return (
    <div className="relative" ref={ref}>
      <button onClick={e => { e.stopPropagation(); setOpen(o => !o) }}
        className="p-1 rounded opacity-0 group-hover:opacity-100 hover:opacity-100 transition-opacity" style={{ color: MUTED }}>
        <MoreHorizontal size={14}/>
      </button>
      {open && (
        <div className="absolute right-0 top-full mt-1 rounded-lg shadow-xl z-30 py-1 min-w-36"
          style={{ backgroundColor: PAPER_LIGHT, border: "1px solid rgba(0,0,0,0.12)" }}>
          {[
            { label: "Edit", icon: <Pencil size={11}/>, action: () => { onEdit(); setOpen(false) } },
            { label: "Archive", icon: <Archive size={11}/>, action: () => { onArchive(); setOpen(false) } },
            { label: "Delete", icon: <Trash2 size={11}/>, action: () => { onDelete(); setOpen(false) }, danger: true },
          ].map(item => (
            <button key={item.label} onClick={e => { e.stopPropagation(); item.action() }}
              className="w-full text-left px-3 py-1.5 text-xs hover:bg-black/5 flex items-center gap-2"
              style={{ fontFamily: F_META, color: item.danger ? INK_RED : INK_BLACK }}>
              <span style={{ color: item.danger ? INK_RED : MUTED }}>{item.icon}</span>{item.label}
            </button>
          ))}
        </div>
      )}
    </div>
  )
}

// ─── CRUD Modals ──────────────────────────────────────────────────────────────

function CreateAreaModal({ open, editing, onClose, onSave }: {
  open: boolean; editing?: Area; onClose: () => void; onSave: (name: string, color: string) => void
}) {
  const [name, setName] = useState("")
  const [color, setColor] = useState(AREA_COLORS[0])
  useEffect(() => { setName(editing?.name || ""); setColor(editing?.color || AREA_COLORS[0]) }, [editing, open])
  return (
    <Modal open={open} onClose={onClose} title={editing ? "Edit Area" : "New Area"}>
      <FIn label="Name" value={name} onChange={setName} placeholder="e.g. Career, Health…"/>
      <ColorPicker selected={color} onChange={setColor}/>
      <div className="flex gap-2 justify-end mt-4">
        <SBtn onClick={onClose}>Cancel</SBtn>
        <PBtn onClick={() => { if (name.trim()) { onSave(name.trim(), color); onClose() } }} disabled={!name.trim()}>
          {editing ? "Save" : "Create"}
        </PBtn>
      </div>
    </Modal>
  )
}

function CreateJourneyModal({ open, editing, areas, defaultAreaId, onClose, onSave }: {
  open: boolean; editing?: Journey; areas: Area[]; defaultAreaId?: string; onClose: () => void
  onSave: (j: Omit<Journey,"id"|"chunks"|"createdDate">) => void
}) {
  const [title, setTitle] = useState(""); const [desc, setDesc] = useState(""); const [deadline, setDeadline] = useState("")
  const [areaId, setAreaId] = useState(defaultAreaId || areas[0]?.id || "")
  const [icon, setIcon] = useState("briefcase"); const [color, setColor] = useState(AREA_COLORS[0])
  useEffect(() => {
    if (!open) return
    if (editing) { setTitle(editing.title); setDesc(editing.description); setDeadline(editing.deadline); setAreaId(editing.areaId); setIcon(editing.iconType); setColor(editing.color) }
    else { setTitle(""); setDesc(""); setDeadline(""); setAreaId(defaultAreaId || areas[0]?.id || ""); setIcon("briefcase"); setColor(areas.find(a => a.id === (defaultAreaId || areas[0]?.id))?.color || AREA_COLORS[0]) }
  }, [open, editing])
  return (
    <Modal open={open} onClose={onClose} title={editing ? "Edit Block" : "New Block"} wide>
      {!editing && areas.length === 0 ? (
        <div className="flex items-start gap-3 py-2 mb-2">
          <AlertCircle size={18} style={{ color: INK_RED, flexShrink: 0, marginTop: 1 }}/>
          <div>
            <p className="text-sm font-medium mb-0.5" style={{ color: INK_BLACK, fontFamily: F_HEAD }}>No areas yet</p>
            <p className="text-xs leading-relaxed" style={{ color: MUTED, fontFamily: F_META }}>
              Blocks must belong to an area. Create an area first using the Areas tab, then come back to add a block.
            </p>
          </div>
        </div>
      ) : (
        <>
      <div className="mb-3">
        <label className="block text-xs font-medium mb-1" style={{ color: MUTED, fontFamily: F_META }}>Area</label>
        <select value={areaId} onChange={e => { setAreaId(e.target.value); const a = areas.find(x => x.id === e.target.value); if (a) setColor(a.color) }}
          className="w-full px-3 py-2 rounded-lg text-sm outline-none border"
          style={{ borderColor: "rgba(0,0,0,0.15)", backgroundColor: "rgba(255,255,255,0.5)", color: INK_BLACK, fontFamily: F_BODY }}>
          {areas.map(a => <option key={a.id} value={a.id}>{a.name}</option>)}
        </select>
      </div>
      <FIn label="Title" value={title} onChange={setTitle} placeholder="e.g. Learn Japanese"/>
      <FTa label="Description" value={desc} onChange={setDesc} placeholder="What's this block about?"/>
      <FIn label="Deadline (optional)" value={deadline} onChange={setDeadline} placeholder="e.g. Jul 1, 2024"/>
      <IconPicker selected={icon} onChange={setIcon}/>
      <ColorPicker selected={color} onChange={setColor}/>
      <div className="flex gap-2 justify-end mt-4">
        <SBtn onClick={onClose}>Cancel</SBtn>
        <PBtn onClick={() => { if (title.trim()) { onSave({ title: title.trim(), description: desc, deadline, areaId, iconType: icon, color }); onClose() } }} disabled={!title.trim()}>
          {editing ? "Save" : "Create"}
        </PBtn>
      </div>
        </>
      )}
      {!editing && areas.length === 0 && (
        <div className="flex justify-end mt-4"><SBtn onClick={onClose}>Close</SBtn></div>
      )}
    </Modal>
  )
}

function CreateChunkModal({ open, editing, journeyId, onClose, onSave }: {
  open: boolean; editing?: Chunk; journeyId: string; onClose: () => void; onSave: (title: string) => void
}) {
  const [title, setTitle] = useState("")
  useEffect(() => { if (!open) return; setTitle(editing?.title || "") }, [open, editing])
  return (
    <Modal open={open} onClose={onClose} title={editing ? "Edit Chunk" : "New Chunk"}>
      <FIn label="Task" value={title} onChange={setTitle} placeholder="What needs to be done?"/>
      <div className="flex gap-2 justify-end mt-4">
        <SBtn onClick={onClose}>Cancel</SBtn>
        <PBtn onClick={() => { if (title.trim()) { onSave(title.trim()); onClose() } }} disabled={!title.trim()}>
          {editing ? "Save" : "Add"}
        </PBtn>
      </div>
    </Modal>
  )
}

function AddToTodayModal({ open, areas, onClose, onToggle }: {
  open: boolean; areas: Area[]; onClose: () => void; onToggle: (cId: string, v: boolean) => void
}) {
  const [search, setSearch] = useState("")
  return (
    <Modal open={open} onClose={onClose} title="Add Chunks to Today" wide>
      <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Search…"
        className="w-full px-3 py-2 rounded-lg text-sm outline-none border mb-3"
        style={{ borderColor: "rgba(0,0,0,0.15)", backgroundColor: "rgba(255,255,255,0.5)", color: INK_BLACK, fontFamily: F_BODY }}/>
      <div className="max-h-80 overflow-y-auto pr-1">
        {areas.length === 0 && (
          <p className="py-4 text-sm text-center" style={{ color: MUTED, fontFamily: F_QUOTE }}>No areas or blocks yet. Create some first!</p>
        )}
        {areas.map(area => {
          const filteredJs = area.journeys.map(j => ({
            ...j, chunks: j.chunks.filter(c => !c.completed && (!search || c.title.toLowerCase().includes(search.toLowerCase())))
          })).filter(j => j.chunks.length > 0)
          if (filteredJs.length === 0) return null
          return (
            <div key={area.id} className="mb-4">
              <div className="flex items-center gap-2 mb-2 pb-1 border-b" style={{ borderColor: "rgba(0,0,0,0.08)" }}>
                <JourneyIcon type="folder" color={area.color} size={20}/>
                <span className="text-sm font-bold" style={{ fontFamily: F_HEAD, color: area.color }}>{area.name}</span>
              </div>
              {filteredJs.map(j => (
                <div key={j.id} className="mb-2 ml-2">
                  <div className="flex items-center gap-1.5 mb-1 flex-wrap">
                    <JourneyIcon type={j.iconType} color={j.color || area.color} size={16}/>
                    <span className="text-xs font-medium" style={{ fontFamily: F_HEAD, color: INK_BLACK }}>{j.title}</span>
                    {j.deadline && (
                      <span className="text-xs px-1.5 py-0.5 rounded-full" style={{ backgroundColor: INK_RED+"15", color: INK_RED, fontFamily: F_META, border: `1px solid ${INK_RED}30` }}>
                        {j.deadline}
                      </span>
                    )}
                  </div>
                  {j.chunks.map(chunk => (
                    <div key={chunk.id} className="flex items-center gap-2.5 py-1.5 px-2 rounded-lg cursor-pointer hover:bg-black/5 ml-2"
                      onClick={() => onToggle(chunk.id, !chunk.isInToday)}>
                      <div className="flex-shrink-0 rounded-sm flex items-center justify-center"
                        style={{ width: 17, height: 17, border: chunk.isInToday ? `2px solid ${INK_RED}` : "1.5px solid rgba(0,0,0,0.25)", backgroundColor: chunk.isInToday ? INK_RED : "transparent" }}>
                        {chunk.isInToday && <Check size={9} color="white" strokeWidth={3}/>}
                      </div>
                      <span className="flex-1 text-sm" style={{ color: INK_BLACK, fontFamily: F_BODY }}>{chunk.title}</span>
                    </div>
                  ))}
                </div>
              ))}
            </div>
          )
        })}
      </div>
      <div className="flex justify-end mt-3"><PBtn onClick={onClose}>Done</PBtn></div>
    </Modal>
  )
}

function ConfirmDelete({ open, label, actionLabel = "Delete", onClose, onConfirm }: {
  open: boolean; label: string; actionLabel?: string; onClose: () => void; onConfirm: () => void
}) {
  const isFullSentence = label.includes("?")
  return (
    <Modal open={open} onClose={onClose} title={actionLabel === "Archive" ? "Confirm Archive" : isFullSentence ? "Confirm Action" : "Confirm Delete"}>
      <div className="flex items-start gap-3 mb-4">
        <AlertCircle size={20} style={{ color: INK_RED, flexShrink: 0, marginTop: 2 }}/>
        <p className="text-sm" style={{ color: INK_BLACK, fontFamily: F_BODY }}>
          {isFullSentence ? label : <>{actionLabel} <strong>{label}</strong>? This cannot be undone.</>}
        </p>
      </div>
      <div className="flex gap-2 justify-end">
        <SBtn onClick={onClose}>Cancel</SBtn>
        <button onClick={() => { onConfirm(); onClose() }} className="px-4 py-2 rounded-lg text-sm"
          style={{ backgroundColor: INK_RED, color: "white", fontFamily: F_BODY }}>{actionLabel}</button>
      </div>
    </Modal>
  )
}

// ─── Profile Modal ────────────────────────────────────────────────────────────

function ProfileModal({ open, onClose, profileName, onSaveName, sidebarQuote, onSaveQuote, rooms, currentRoomId, onAddRoom, onDeleteRoom, onSwitchRoom, tracks, onAddTrack, onDeleteTrack, onExport, onImport }: {
  open: boolean; onClose: () => void; profileName: string; onSaveName: (n: string) => void
  sidebarQuote: string; onSaveQuote: (q: string) => void
  rooms: Room[]; currentRoomId: string; onAddRoom: (n: string, i: string) => void
  onDeleteRoom: (id: string) => void; onSwitchRoom: (id: string) => void
  tracks: MusicTrack[]; onAddTrack: (n: string) => void; onDeleteTrack: (id: string) => void
  onExport: () => void; onImport: (f: File) => void
}) {
  const [name, setName] = useState(profileName)
  const [quoteVal, setQuoteVal] = useState(sidebarQuote)
  useEffect(() => { setQuoteVal(sidebarQuote) }, [sidebarQuote, open])
  const [newRoomName, setNewRoomName] = useState(""); const [pendingImg, setPendingImg] = useState<string|null>(null)
  const [newTrackName, setNewTrackName] = useState("")
  const roomRef = useRef<HTMLInputElement>(null); const trackRef = useRef<HTMLInputElement>(null); const importRef = useRef<HTMLInputElement>(null)
  useEffect(() => { setName(profileName) }, [profileName, open])

  const Sec = ({ label }: { label: string }) => (
    <h3 className="text-xs font-bold uppercase tracking-widest mb-2 mt-4" style={{ color: MUTED, fontFamily: F_HEAD }}>{label}</h3>
  )
  return (
    <Modal open={open} onClose={onClose} title="Profile & Settings" wide>
      <Sec label="Data"/>
      <div className="flex gap-2 mb-1">
        <button onClick={onExport} className="flex-1 flex items-center justify-center gap-2 py-2 rounded-lg text-sm border"
          style={{ borderColor: "rgba(0,0,0,0.15)", color: INK_BLACK, fontFamily: F_BODY }}>
          <Download size={14}/> Export JSON
        </button>
        <button onClick={() => importRef.current?.click()} className="flex-1 flex items-center justify-center gap-2 py-2 rounded-lg text-sm border"
          style={{ borderColor: "rgba(0,0,0,0.15)", color: INK_BLACK, fontFamily: F_BODY }}>
          <Upload size={14}/> Import JSON
        </button>
        <input ref={importRef} type="file" accept=".json" className="hidden"
          onChange={e => { const f = e.target.files?.[0]; if (f) onImport(f); e.target.value = "" }}/>
      </div>
      <Sec label="Display Name"/>
      <div className="flex gap-2 mb-1">
        <input value={name} onChange={e => setName(e.target.value)} placeholder="Your name"
          className="flex-1 px-3 py-2 rounded-lg text-sm outline-none border"
          style={{ borderColor: "rgba(0,0,0,0.15)", backgroundColor: "rgba(255,255,255,0.5)", color: INK_BLACK, fontFamily: F_BODY }}/>
        <PBtn onClick={() => onSaveName(name)}>Save</PBtn>
      </div>
      <Sec label="Sidebar Quote"/>
      <div className="flex gap-2 mb-1">
        <textarea value={quoteVal} onChange={e => setQuoteVal(e.target.value)} rows={2}
          placeholder="Type your motivational quote…"
          className="flex-1 px-3 py-2 rounded-lg text-sm outline-none border resize-none"
          style={{ borderColor: "rgba(0,0,0,0.15)", backgroundColor: "rgba(255,255,255,0.5)", color: INK_BLACK, fontFamily: F_QUOTE, fontSize: "1rem" }}/>
        <PBtn onClick={() => onSaveQuote(quoteVal)}>Save</PBtn>
      </div>
      <Sec label="Rooms"/>
      <div className="flex flex-col gap-1.5 mb-2 max-h-32 overflow-y-auto">
        {rooms.map(r => (
          <div key={r.id} className="flex items-center gap-2 px-2 py-1.5 rounded-lg"
            style={{ backgroundColor: r.id === currentRoomId ? INK_RED+"18" : "rgba(0,0,0,0.04)" }}>
            <div className="w-10 h-7 rounded overflow-hidden flex-shrink-0">
              <img src={r.bgImage} alt={r.name} className="w-full h-full object-cover"/>
            </div>
            <span className="flex-1 text-sm" style={{ fontFamily: F_BODY, color: INK_BLACK, fontWeight: r.id === currentRoomId ? 600 : 400 }}>{r.name}</span>
            {r.id !== currentRoomId && (
              <button onClick={() => onSwitchRoom(r.id)} className="text-xs px-2 py-0.5 rounded" style={{ color: INK_RED, fontFamily: F_BODY }}>Use</button>
            )}
            {r.id === currentRoomId && <span className="text-xs" style={{ color: INK_RED, fontFamily: F_QUOTE }}>Active</span>}
            {rooms.length > 1 && (
              <button onClick={() => onDeleteRoom(r.id)} style={{ color: MUTED }}><Trash2 size={13}/></button>
            )}
          </div>
        ))}
      </div>
      <div className="flex gap-2">
        <input value={newRoomName} onChange={e => setNewRoomName(e.target.value)} placeholder="Room name"
          className="flex-1 px-3 py-2 rounded-lg text-sm outline-none border"
          style={{ borderColor: "rgba(0,0,0,0.15)", backgroundColor: "rgba(255,255,255,0.5)", color: INK_BLACK, fontFamily: F_BODY }}/>
        <button onClick={() => roomRef.current?.click()} className="px-3 py-2 rounded-lg text-sm border"
          style={{ borderColor: "rgba(0,0,0,0.15)", color: pendingImg ? INK_RED : MUTED, fontFamily: F_BODY, backgroundColor: "rgba(255,255,255,0.5)" }}>
          {pendingImg ? "✓ Photo" : "Photo"}
        </button>
        <input ref={roomRef} type="file" accept="image/*" className="hidden" onChange={e => {
          const f = e.target.files?.[0]; if (!f) return
          const r = new FileReader(); r.onload = ev => setPendingImg(ev.target?.result as string); r.readAsDataURL(f)
        }}/>
        <PBtn onClick={() => { if (newRoomName && pendingImg) { onAddRoom(newRoomName, pendingImg); setNewRoomName(""); setPendingImg(null) } }} disabled={!newRoomName || !pendingImg}>Add</PBtn>
      </div>
      <Sec label="Music"/>
      <div className="flex flex-col gap-1 mb-2 max-h-32 overflow-y-auto">
        {tracks.map(t => (
          <div key={t.id} className="flex items-center gap-2 px-2 py-1.5 rounded-lg" style={{ backgroundColor: "rgba(0,0,0,0.04)" }}>
            <Music2 size={13} style={{ color: MUTED, flexShrink: 0 }}/>
            <span className="flex-1 text-sm" style={{ fontFamily: F_BODY, color: INK_BLACK }}>{t.name}</span>
            {t.isBuiltIn && <span className="text-xs px-1.5 py-0.5 rounded" style={{ backgroundColor: "rgba(0,0,0,0.08)", color: MUTED, fontFamily: F_META }}>Built-in</span>}
            {!t.isBuiltIn && <button onClick={() => onDeleteTrack(t.id)} style={{ color: MUTED }}><Trash2 size={13}/></button>}
          </div>
        ))}
      </div>
      <div className="flex gap-2">
        <input value={newTrackName} onChange={e => setNewTrackName(e.target.value)} placeholder="Track name"
          className="flex-1 px-3 py-2 rounded-lg text-sm outline-none border"
          style={{ borderColor: "rgba(0,0,0,0.15)", backgroundColor: "rgba(255,255,255,0.5)", color: INK_BLACK, fontFamily: F_BODY }}/>
        <button onClick={() => trackRef.current?.click()} className="px-3 py-2 rounded-lg text-sm border flex items-center gap-1"
          style={{ borderColor: "rgba(0,0,0,0.15)", color: MUTED, fontFamily: F_BODY, backgroundColor: "rgba(255,255,255,0.5)" }}>
          <Upload size={12}/> File
        </button>
        <input ref={trackRef} type="file" accept="audio/*" className="hidden" onChange={e => {
          const f = e.target.files?.[0]; if (!f) return
          onAddTrack(newTrackName.trim() || f.name.replace(/\.[^.]+$/, ""))
          setNewTrackName(""); e.target.value = ""
        }}/>
        <PBtn onClick={() => { if (newTrackName.trim()) { onAddTrack(newTrackName.trim()); setNewTrackName("") } }} disabled={!newTrackName.trim()}>Add</PBtn>
      </div>
      <div className="flex justify-end mt-5"><PBtn onClick={onClose}>Close</PBtn></div>
    </Modal>
  )
}

// ─── Music dropdown ───────────────────────────────────────────────────────────

function MusicDropdown({ open, onClose, tracks, currentTrackId, playing, volume, onSelectTrack, onTogglePlay, onVolumeChange }: {
  open: boolean; onClose: () => void; tracks: MusicTrack[]
  currentTrackId: string|null; playing: boolean; volume: number
  onSelectTrack: (id: string) => void; onTogglePlay: () => void; onVolumeChange: (v: number) => void
}) {
  if (!open) return null
  return (
    <div className="fixed inset-0 z-40" onClick={e => { if (e.target === e.currentTarget) onClose() }}>
      <div className="absolute top-11 right-24 rounded-xl p-4 shadow-2xl w-72"
        style={{ backgroundColor: PAPER_LIGHT, border: "1px solid rgba(0,0,0,0.12)" }}>
        <div className="flex items-center justify-between mb-3">
          <span className="text-sm font-bold" style={{ fontFamily: F_HEAD, color: INK_BLACK }}>Music</span>
          <button onClick={onClose} style={{ color: MUTED }}><X size={14}/></button>
        </div>
        <div className="flex flex-col gap-1 mb-3 max-h-44 overflow-y-auto">
          {tracks.map(t => (
            <div key={t.id} className="flex items-center gap-2 px-2 py-1.5 rounded-lg cursor-pointer"
              style={{ backgroundColor: currentTrackId === t.id ? INK_RED+"18" : "transparent" }}
              onClick={() => onSelectTrack(t.id)}>
              <Music2 size={12} style={{ color: currentTrackId === t.id ? INK_RED : MUTED, flexShrink: 0 }}/>
              <span className="flex-1 text-sm" style={{ color: currentTrackId === t.id ? INK_RED : INK_BLACK, fontFamily: F_BODY }}>{t.name}</span>
              {currentTrackId === t.id && playing && <span style={{ color: INK_RED, fontSize: "0.7rem" }}>▶</span>}
            </div>
          ))}
        </div>
        <div className="flex items-center gap-2 mb-3">
          {volume === 0 ? <VolumeX size={14} style={{ color: MUTED }}/> : <Volume2 size={14} style={{ color: MUTED }}/>}
          <input type="range" min="0" max="1" step="0.05" value={volume}
            onChange={e => onVolumeChange(Number(e.target.value))} className="flex-1" style={{ accentColor: INK_RED }}/>
          <span className="text-xs w-8" style={{ color: MUTED, fontFamily: F_META }}>{Math.round(volume*100)}%</span>
        </div>
        <button onClick={onTogglePlay} className="w-full flex items-center justify-center gap-2 py-2 rounded-lg"
          style={{ backgroundColor: playing ? "rgba(0,0,0,0.08)" : INK_RED, color: playing ? INK_BLACK : "white", fontFamily: F_QUOTE, fontSize: "1rem" }}>
          {playing ? <><Pause size={14}/> Pause</> : <><Play size={14} fill="currentColor"/> Play</>}
        </button>
      </div>
    </div>
  )
}

